import{c as a,Q as s,j as e,m as n}from"./chunks/framework.Bhbi9jCp.js";const b=JSON.parse('{"title":"音视频质量评估与排障","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/28-音视频质量评估与排障.md","filePath":"mediaTechLearning/28-音视频质量评估与排障.md","lastUpdated":1780887690000}'),i={name:"mediaTechLearning/28-音视频质量评估与排障.md"};function d(l,t,r,p,o,h){return s(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="音视频质量评估与排障" tabindex="-1">音视频质量评估与排障 <a class="header-anchor" href="#音视频质量评估与排障" aria-label="Permalink to &quot;音视频质量评估与排障&quot;">​</a></h1><p>音视频线上问题最怕一句&quot;用户说卡&quot;。你必须把卡拆成可观测指标。</p><blockquote><p>一句话先记住:<strong>质量问题要按链路定位:采集、编码、上行、服务端、分发、播放、设备</strong>。没有指标,只能猜。</p></blockquote><hr><h2 id="一、核心指标" tabindex="-1">一、核心指标 <a class="header-anchor" href="#一、核心指标" aria-label="Permalink to &quot;一、核心指标&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>首帧时间</td><td>点击到出画面</td></tr><tr><td>卡顿次数</td><td>播放中断次数</td></tr><tr><td>卡顿时长</td><td>中断总时长</td></tr><tr><td>RTT</td><td>往返延迟</td></tr><tr><td>packet loss</td><td>丢包</td></tr><tr><td>jitter</td><td>抖动</td></tr><tr><td>bitrate</td><td>实际码率</td></tr><tr><td>fps</td><td>实际帧率</td></tr><tr><td>dropped frames</td><td>丢帧</td></tr><tr><td>audio level</td><td>音量</td></tr></tbody></table><p>会议和播放器都要打点。</p><hr><h2 id="二、webrtc-排障顺序" tabindex="-1">二、WebRTC 排障顺序 <a class="header-anchor" href="#二、webrtc-排障顺序" aria-label="Permalink to &quot;二、WebRTC 排障顺序&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 信令通了吗?</span></span>
<span class="line"><span>2. SDP setLocal / setRemote 成功了吗?</span></span>
<span class="line"><span>3. ICE connected 了吗?</span></span>
<span class="line"><span>4. candidate 类型是什么? host / srflx / relay?</span></span>
<span class="line"><span>5. getStats 有 bytesSent / bytesReceived 吗?</span></span>
<span class="line"><span>6. 有包但没画面? 查解码 / track / autoplay</span></span>
<span class="line"><span>7. 有画面但卡? 查 RTT / loss / jitter / bitrate</span></span></code></pre></div><p>不要一上来怀疑编码器。</p><hr><h2 id="三、播放器排障顺序" tabindex="-1">三、播放器排障顺序 <a class="header-anchor" href="#三、播放器排障顺序" aria-label="Permalink to &quot;三、播放器排障顺序&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. manifest 能下载吗?</span></span>
<span class="line"><span>2. segment 能下载吗?</span></span>
<span class="line"><span>3. MIME 对吗?</span></span>
<span class="line"><span>4. CORS 对吗?</span></span>
<span class="line"><span>5. 编码支持吗?</span></span>
<span class="line"><span>6. 时间戳正常吗?</span></span>
<span class="line"><span>7. 缓冲增长吗?</span></span>
<span class="line"><span>8. 解码掉帧吗?</span></span></code></pre></div><p>浏览器 DevTools Network 面板是第一现场。</p><hr><h2 id="四、ffmpeg-排障" tabindex="-1">四、FFmpeg 排障 <a class="header-anchor" href="#四、ffmpeg-排障" aria-label="Permalink to &quot;四、FFmpeg 排障&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -hide_banner</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -show_streams</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -show_format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span></span></code></pre></div><p>看:</p><ul><li>codec</li><li>pix_fmt</li><li>time_base</li><li>duration</li><li>bit_rate</li><li>frame rate</li><li>start_time</li></ul><p>转码失败一定保存完整 stderr。</p><hr><h2 id="五、常见故障表" tabindex="-1">五、常见故障表 <a class="header-anchor" href="#五、常见故障表" aria-label="Permalink to &quot;五、常见故障表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>常见原因</th></tr></thead><tbody><tr><td>本地通线上不通</td><td>NAT / TURN / 防火墙</td></tr><tr><td>有声音没画面</td><td>视频编码不支持 / track 没绑定</td></tr><tr><td>画面糊</td><td>码率低 / 分辨率降级 / 丢包</td></tr><tr><td>声音断</td><td>丢包 / jitter / 音频设备问题</td></tr><tr><td>HLS 拖动卡</td><td>关键帧 / 分片 / 时间戳</td></tr><tr><td>首帧慢</td><td>清单慢 / 分片慢 / 缓冲策略</td></tr></tbody></table><hr><h2 id="六、踩坑提醒" tabindex="-1">六、踩坑提醒 <a class="header-anchor" href="#六、踩坑提醒" aria-label="Permalink to &quot;六、踩坑提醒&quot;">​</a></h2><ol><li><strong>只收业务日志</strong>——音视频必须收媒体指标。</li><li><strong>不区分上行和下行</strong>。</li><li><strong>不记录设备和浏览器版本</strong>。</li><li><strong>服务端无房间级指标</strong>。</li><li><strong>不保存失败样本</strong>——无法复现。</li></ol><p>下一篇:<code>29-带宽、CDN、存储与成本.md</code>。</p>`,28)])])}const g=a(i,[["render",d]]);export{b as __pageData,g as default};
